/// job given message on basis of marks and age

#include <iostream>
using namespace std;
int main ( )
{
int marks,age;

cout&lt;&lt;"\nEnter your Marks ";
cin&gt;&gt;marks;
cout&lt;&lt;"\nEnter your age ";
cin&gt;&gt;age;

if(marks&gt;=60)
{
if(age&gt;=18)
{
cout&lt;&lt;"you got the job";
}
}
cout&lt;&lt;" Good Luck";
return 0;
